var CONVERSATIONS_AR_EN = [
{ title: "طلب قهوة في مقهى", scene: "أنت في مقهى صغير في لندن في الصباح. تريد طلب قهوة وشطيرة، وتحتاج إلى معرفة إن كان بإمكانك الدفع بالبطاقة.", lines: [{ who: "them", en: "Good morning, what can I get for you?", ar: "صباح الخير، ماذا أحضر لك؟" }, { who: "you", en: "Good morning, I would like a coffee, please.", ar: "صباح الخير، أود قهوة من فضلك." }, { who: "them", en: "What size would you like?", ar: "أي حجم تريد؟" }, { who: "you", en: "Medium, please.", ar: "متوسط، من فضلك." }, { who: "them", en: "Would you like milk or sugar?", ar: "هل تريد حليباً أو سكراً؟" }, { who: "you", en: "Milk, please, but no sugar.", ar: "حليب من فضلك، لكن بدون سكر." }, { who: "them", en: "Anything else?", ar: "هل تريد شيئاً آخر؟" }, { who: "you", en: "Yes, a chicken sandwich, please.", ar: "نعم، شطيرة دجاج من فضلك." }, { who: "them", en: "For here or to go?", ar: "هنا أم سفري؟" }, { who: "you", en: "To go, please. Can I pay by card?", ar: "سفري من فضلك. هل يمكنني الدفع بالبطاقة؟" }, { who: "them", en: "Yes, of course.", ar: "نعم، بالتأكيد." }, { who: "you", en: "Thank you.", ar: "شكراً." }] },
{ title: "تسجيل الدخول في الفندق", scene: "وصلت إلى فندق في نيويورك بعد رحلة طويلة. تذهب إلى مكتب الاستقبال لتأكيد الحجز والسؤال عن الفطور ووقت الخروج.", lines: [{ who: "them", en: "Welcome to the hotel. How can I help you?", ar: "أهلاً بك في الفندق. كيف يمكنني مساعدتك؟" }, { who: "you", en: "Hello, I have a reservation.", ar: "مرحباً، لدي حجز." }, { who: "them", en: "What is your name, please?", ar: "ما اسمك من فضلك؟" }, { who: "you", en: "My name is Omar Hassan.", ar: "اسمي عمر حسن." }, { who: "them", en: "May I see your passport?", ar: "هل يمكنني رؤية جواز سفرك؟" }, { who: "you", en: "Yes, here is my passport.", ar: "نعم، هذا جواز سفري." }, { who: "them", en: "Your room is on the fifth floor.", ar: "غرفتك في الطابق الخامس." }, { who: "you", en: "Thank you. Is breakfast included?", ar: "شكراً. هل الفطور مشمول؟" }, { who: "them", en: "Yes, breakfast is from seven to ten.", ar: "نعم، الفطور من السابعة إلى العاشرة." }, { who: "you", en: "Great. What time is check-out?", ar: "رائع. متى وقت تسجيل الخروج؟" }, { who: "them", en: "Check-out is at eleven.", ar: "تسجيل الخروج في الساعة الحادية عشرة." }, { who: "you", en: "Thank you for your help.", ar: "شكراً على مساعدتك." }] },
{ title: "السؤال عن الاتجاهات", scene: "أنت في وسط إدنبرة وتبحث عن المتحف الوطني. هاتفك يعمل، لكنك تريد تأكيد الطريق مع شخص محلي.", lines: [{ who: "you", en: "Excuse me, can I ask a question?", ar: "عذراً، هل يمكنني أن أسأل سؤالاً؟" }, { who: "them", en: "Yes, of course.", ar: "نعم، بالتأكيد." }, { who: "you", en: "Where is the National Museum?", ar: "أين المتحف الوطني؟" }, { who: "them", en: "It is near here.", ar: "إنه قريب من هنا." }, { who: "you", en: "Can I walk there?", ar: "هل يمكنني المشي إلى هناك؟" }, { who: "them", en: "Yes, go straight and turn left at the corner.", ar: "نعم، امشِ للأمام وانعطف يساراً عند الزاوية." }, { who: "you", en: "How long will it take?", ar: "كم سيستغرق الوقت؟" }, { who: "them", en: "About ten minutes.", ar: "حوالي عشر دقائق." }, { who: "you", en: "Can you show me on the map?", ar: "هل يمكنك أن تريني على الخريطة؟" }, { who: "them", en: "Sure, it is here.", ar: "بالتأكيد، إنه هنا." }, { who: "you", en: "Thank you very much.", ar: "شكراً جزيلاً." }, { who: "them", en: "You are welcome.", ar: "على الرحب والسعة." }] },
{ title: "في مطعم للعشاء", scene: "أنت في مطعم في بوسطن مع صديق. تريد طاولة لشخصين، وتسأل عن توصية، ثم تطلب الفاتورة.", lines: [{ who: "them", en: "Good evening. Do you have a reservation?", ar: "مساء الخير. هل لديكم حجز؟" }, { who: "you", en: "No, we do not. A table for two, please.", ar: "لا، ليس لدينا. طاولة لشخصين من فضلك." }, { who: "them", en: "Please follow me.", ar: "تفضلا اتبعاني." }, { who: "you", en: "Thank you. Can we see the menu?", ar: "شكراً. هل يمكننا رؤية القائمة؟" }, { who: "them", en: "Of course. Here you are.", ar: "بالطبع. تفضلا." }, { who: "you", en: "What do you recommend?", ar: "ماذا تنصح؟" }, { who: "them", en: "The grilled fish is very popular.", ar: "السمك المشوي مشهور جداً." }, { who: "you", en: "Does it have dairy?", ar: "هل يحتوي على ألبان؟" }, { who: "them", en: "No, it does not.", ar: "لا، لا يحتوي." }, { who: "you", en: "Great, I would like the grilled fish.", ar: "رائع، أود السمك المشوي." }, { who: "them", en: "Excellent choice.", ar: "اختيار ممتاز." }, { who: "you", en: "Later, can we have the bill, please?", ar: "لاحقاً، هل يمكننا الحصول على الفاتورة من فضلك؟" }] },
{ title: "شراء تذكرة قطار", scene: "أنت في محطة قطار في لندن وتريد الذهاب إلى أكسفورد. تحتاج إلى تذكرة وتسأل عن الرصيف الصحيح.", lines: [{ who: "them", en: "Hello, how can I help?", ar: "مرحباً، كيف أساعدك؟" }, { who: "you", en: "I need a ticket to Oxford, please.", ar: "أحتاج تذكرة إلى أكسفورد من فضلك." }, { who: "them", en: "Single or return?", ar: "ذهاب فقط أم ذهاب وعودة؟" }, { who: "you", en: "Return, please.", ar: "ذهاب وعودة، من فضلك." }, { who: "them", en: "That is twenty pounds.", ar: "السعر عشرون جنيهاً." }, { who: "you", en: "Can I pay by card?", ar: "هل يمكنني الدفع بالبطاقة؟" }, { who: "them", en: "Yes, please tap your card.", ar: "نعم، من فضلك مرر بطاقتك." }, { who: "you", en: "Thank you. Which platform is it?", ar: "شكراً. أي رصيف للقطار؟" }, { who: "them", en: "Platform three.", ar: "الرصيف الثالث." }, { who: "you", en: "How many stops?", ar: "كم محطة؟" }, { who: "them", en: "It is a direct train.", ar: "إنه قطار مباشر." }, { who: "you", en: "Great, thank you.", ar: "رائع، شكراً." }] },
{ title: "التسوّق في متجر ملابس", scene: "أنت في متجر ملابس في تورونتو. أعجبك قميص، لكنك تحتاج إلى مقاس مختلف وتريد معرفة إن كان هناك خصم.", lines: [{ who: "them", en: "Hi, can I help you?", ar: "أهلاً، هل يمكنني مساعدتك؟" }, { who: "you", en: "Hi, I am just looking.", ar: "أهلاً، أنا فقط أتفرج." }, { who: "them", en: "No problem.", ar: "لا مشكلة." }, { who: "you", en: "Do you have this shirt in medium?", ar: "هل لديكم هذا القميص بمقاس متوسط؟" }, { who: "them", en: "Yes, here you go.", ar: "نعم، تفضل." }, { who: "you", en: "Can I try it on?", ar: "هل يمكنني تجربته؟" }, { who: "them", en: "Of course, the fitting room is over there.", ar: "بالطبع، غرفة القياس هناك." }, { who: "you", en: "Thank you. Is there a discount?", ar: "شكراً. هل يوجد خصم؟" }, { who: "them", en: "Yes, it is ten percent off today.", ar: "نعم، عليه خصم عشرة بالمئة اليوم." }, { who: "you", en: "Great. I will take it.", ar: "رائع. سأشتريه." }, { who: "them", en: "Would you like a bag?", ar: "هل تريد كيساً؟" }, { who: "you", en: "Yes, please.", ar: "نعم، من فضلك." }] },
{ title: "في الصيدلية", scene: "أنت في صيدلية في شيكاغو وتشعر بصداع بعد يوم طويل. تريد دواء بسيطاً وتسأل عن طريقة الاستخدام.", lines: [{ who: "them", en: "Hello, how can I help you?", ar: "مرحباً، كيف يمكنني مساعدتك؟" }, { who: "you", en: "Hello, I have a headache.", ar: "مرحباً، لدي صداع." }, { who: "them", en: "Do you have a fever?", ar: "هل لديك حمى؟" }, { who: "you", en: "No, I do not have a fever.", ar: "لا، ليس لدي حمى." }, { who: "them", en: "Do you have any allergies?", ar: "هل لديك أي حساسية؟" }, { who: "you", en: "I have a nut allergy, but no medicine allergy.", ar: "لدي حساسية من المكسرات، لكن لا حساسية من الدواء." }, { who: "them", en: "This medicine may help.", ar: "هذا الدواء قد يساعد." }, { who: "you", en: "How often should I take it?", ar: "كم مرة يجب أن آخذه؟" }, { who: "them", en: "Take it every six hours with water.", ar: "خذه كل ست ساعات مع الماء." }, { who: "you", en: "Do I need a doctor?", ar: "هل أحتاج إلى طبيب؟" }, { who: "them", en: "If the pain gets worse, yes.", ar: "إذا أصبح الألم أسوأ، نعم." }, { who: "you", en: "Thank you for your help.", ar: "شكراً على مساعدتك." }] },
{ title: "حديث بسيط مع شخص محلي", scene: "أنت جالس في قطار في أستراليا ويتحدث معك شخص محلي بلطف. تريد أن تكون ودوداً وتستخدم جملاً بسيطة عن رحلتك.", lines: [{ who: "you", en: "Hello, is this seat free?", ar: "مرحباً، هل هذا المقعد فارغ؟" }, { who: "them", en: "Yes, it is. Please sit down.", ar: "نعم، تفضل بالجلوس." }, { who: "you", en: "Thank you. I am visiting from Morocco.", ar: "شكراً. أنا أزور من المغرب." }, { who: "them", en: "Nice. Are you here on vacation?", ar: "جميل. هل أنت هنا في إجازة؟" }, { who: "you", en: "Yes, I am here on vacation.", ar: "نعم، أنا هنا في إجازة." }, { who: "them", en: "How do you like the city?", ar: "كيف وجدت المدينة؟" }, { who: "you", en: "This city is beautiful, and people are friendly.", ar: "هذه المدينة جميلة، والناس ودودون." }, { who: "them", en: "I am glad to hear that.", ar: "يسعدني سماع ذلك." }, { who: "you", en: "How long have you lived here?", ar: "منذ متى تعيش هنا؟" }, { who: "them", en: "I have lived here for ten years.", ar: "أعيش هنا منذ عشر سنوات." }, { who: "you", en: "That is interesting. I like the food here.", ar: "هذا مثير للاهتمام. يعجبني الطعام هنا." }, { who: "them", en: "You should try the local seafood.", ar: "يجب أن تجرب المأكولات البحرية المحلية." }] }
];
